import json
import time

import pytest
from hypothesis import given, settings, strategies as st
from hypothesis.stateful import RuleBasedStateMachine, rule, invariant, initialize

from .conftest import seed_member, seed_dnd


# ---------------------------------------------------------------------------
# PBT 1 — atomicity of dispatch across surfaces and counters
# Property: invariant (REQ-001 + REQ-002).
# Claim: for every mention event, after dispatch either
#   (a) at least one surface in successful_surfaces AND counters reflect it, or
#   (b) zero surfaces AND counters unchanged.
# There must be no "half-dispatched" state where surfaces[] fired but
# counters did not increment, or vice versa.
# ---------------------------------------------------------------------------

class MentionDispatchAtomicityMachine(RuleBasedStateMachine):
    """Property: invariant (atomicity) — REQ-001 + REQ-002 cross-surface integrity."""

    @initialize()
    def _seed(self):
        from .conftest import seed_member as _sm
        # The fixtures are class attributes injected by the wrapper test below.
        _sm(self.db, "m_target", channels=["c1"])
        _sm(self.db, "m99", channels=["c1"])

    @rule(dnd_on=st.booleans())
    def send_mention(self, dnd_on):
        # set DND
        self.http.put("/api/members/m_target/dnd", json={"manual_on": dnd_on})

        counts_before = self.db.execute(
            "SELECT unread_badge_count, unread_mention_count FROM member_counters WHERE member_id = %s",
            ["m_target"],
        ).fetchone() or (0, 0)

        resp = self.http.post("/api/messages", json={
            "channel_id": "c1", "author_id": "m99",
            "body": "hey @m_target", "mention_ids": ["m_target"],
            "mention_kind": "individual",
        })
        assert resp.status_code == 200

        # Atomicity check
        dispatch = self.db.execute(
            "SELECT successful_surfaces FROM mention_dispatch WHERE mentioned_id = %s "
            "ORDER BY created_at DESC LIMIT 1",
            ["m_target"],
        ).fetchone()
        counts_after = self.db.execute(
            "SELECT unread_badge_count, unread_mention_count FROM member_counters WHERE member_id = %s",
            ["m_target"],
        ).fetchone()

        surfaces = set(dispatch[0]) if dispatch else set()
        badge_delta = counts_after[0] - counts_before[0]
        mention_delta = counts_after[1] - counts_before[1]

        # Per glossary 'silence': badge & unread_count tick under DND too.
        # Per REQ-001: at least one surface fires when delivered; counters reflect.
        # Invariant: counter increments by exactly 1 AND surfaces non-empty,
        # OR both unchanged (only legal for "skipped" recipients — which
        # m_target isn't, since they ARE a channel member).
        assert badge_delta == mention_delta, \
            f"counter drift: badge_delta={badge_delta} mention_delta={mention_delta}"
        if dnd_on:
            # silence: badge+1, no push in surfaces but at least 'unread_badge'.
            assert badge_delta == 1, f"silenced mention did not tick badge: {badge_delta}"
            assert "push" not in surfaces, "push fired under DND"
            assert "banner" not in surfaces, "banner fired under DND"
            assert "sound" not in surfaces, "sound fired under DND"
        else:
            assert badge_delta == 1, f"un-silenced mention did not tick badge: {badge_delta}"
            assert surfaces, "no surface fired in non-DND state"


@pytest.mark.integration
def test_mention_dispatch_atomicity_across_surfaces_and_counters_invariant(http_client, db):
    """Property: invariant (REQ-001+REQ-002). Cross-boundary dispatch atomicity."""
    machine_cls = MentionDispatchAtomicityMachine
    machine_cls.http = http_client
    machine_cls.db = db
    machine_cls.TestCase.settings = settings(
        max_examples=500, deadline=None, stateful_step_count=15,
    )
    machine_cls.TestCase().runTest()


# ---------------------------------------------------------------------------
# PBT 2 — per-channel mute consistency across restart
# Property: invariant (REQ-002). Muting a channel for member m must continue
# to silence mentions in that channel even after a simulated app restart
# (the app object is rebuilt against the same Postgres + Redis).
# ---------------------------------------------------------------------------

@settings(max_examples=500, deadline=None)
@given(
    muted_channels=st.lists(
        st.sampled_from(["c_a", "c_b", "c_c"]),
        min_size=0, max_size=3, unique=True,
    ),
    mention_channel=st.sampled_from(["c_a", "c_b", "c_c"]),
)
def test_per_channel_mute_consistently_silences_across_restart_invariant(
    http_client, db, postgres_url, redis_url, muted_channels, mention_channel,
):
    """Property: invariant (REQ-002 muted-channels arm). Mute persists across restart."""
    # Reset member state
    db.execute("DELETE FROM member_counters WHERE member_id = 'mp'")
    db.execute("DELETE FROM mention_dispatch WHERE mentioned_id = 'mp'")

    seed_member(db, "mp", channels=["c_a", "c_b", "c_c"])
    seed_member(db, "m99", channels=["c_a", "c_b", "c_c"])
    seed_dnd(db, "mp", manual_on=False, muted_channels=muted_channels)

    # Simulate restart: rebuild the app against same DB & Redis.
    from src.app import make_app
    fresh_app = make_app(db_url=postgres_url, redis_url=redis_url)
    from starlette.testclient import TestClient
    fresh_client = TestClient(fresh_app)

    resp = fresh_client.post("/api/messages", json={
        "channel_id": mention_channel, "author_id": "m99",
        "body": "hi @mp", "mention_ids": ["mp"], "mention_kind": "individual",
    })
    assert resp.status_code == 200

    dispatch = db.execute(
        "SELECT successful_surfaces FROM mention_dispatch WHERE mentioned_id = 'mp' "
        "ORDER BY created_at DESC LIMIT 1",
    ).fetchone()
    surfaces = set(dispatch[0]) if dispatch else set()

    if mention_channel in muted_channels:
        # Muted → silence rule applies, exactly as if DND were on.
        assert "push" not in surfaces, f"push fired in muted channel {mention_channel}"
        assert "banner" not in surfaces, f"banner fired in muted channel {mention_channel}"
        assert "sound" not in surfaces, f"sound fired in muted channel {mention_channel}"
    else:
        # Not muted → at least one external surface fired.
        assert ({"push", "banner", "sound"} & surfaces), \
            f"no external surface fired for non-muted channel: {surfaces}"
